return items.map(item => {
  const root = item.json || {};
  const envelope = root.body && typeof root.body === 'object' ? root.body : root;
  const msg = envelope.message || envelope.data || root.message || root.data || {};

  const findDeep = (obj, predicate) => {
    const seen = new Set();
    const stack = [obj];
    while (stack.length) {
      const cur = stack.pop();
      if (!cur || typeof cur !== 'object') continue;
      if (seen.has(cur)) continue;
      seen.add(cur);
      if (predicate(cur)) return cur;
      for (const v of Object.values(cur)) {
        if (v && typeof v === 'object') stack.push(v);
      }
    }
    return null;
  };

  const callObj = msg.call || envelope.call || root.call ||
    findDeep(msg, (x) => x.id && (x.startedAt || x.endedAt || x.customer || x.metadata));

  const metadata = (callObj && callObj.metadata) || msg.metadata || envelope.metadata || root.metadata || {};

  const startedAt = (callObj && callObj.startedAt) || msg.startedAt || envelope.startedAt || root.startedAt || null;
  const endedAt = (callObj && callObj.endedAt) || msg.endedAt || envelope.endedAt || root.endedAt || null;
  const endedReason = msg.endedReason || envelope.endedReason || root.endedReason || null;
  const eventType = msg.type || envelope.type || root.type || null;
  const callId = (callObj && callObj.id) || msg.id || envelope.id || root.id || null;
  const customer = (callObj && callObj.customer) || msg.customer || envelope.customer || root.customer || {};

  const transcript = msg.transcript || envelope.transcript || root.transcript ||
    (msg.artifact && msg.artifact.transcript) || null;
  const recordingUrl = msg.recordingUrl || envelope.recordingUrl || root.recordingUrl ||
    (msg.artifact && msg.artifact.recordingUrl) || null;
  const summary = msg.summary || envelope.summary || root.summary || null;

  const durationMs = msg.durationMs || envelope.durationMs || root.durationMs || null;
  const durationSeconds = msg.durationSeconds || envelope.durationSeconds || root.durationSeconds ||
    (durationMs ? Math.round(durationMs / 1000) : null);

  const cost = msg.cost || envelope.cost || root.cost || 0;

  const artifact = msg.artifact || envelope.artifact || root.artifact || {};
  const structuredOutputs = artifact.structuredOutputs || msg.structuredOutputs ||
    envelope.structuredOutputs || root.structuredOutputs || {};

  const transfers = artifact.transfers || msg.transfers || envelope.transfers || root.transfers || [];

  item.json = {
    id_negocio: metadata.id_negocio || null,
    cedula: metadata.cedula || null,
    id_llamada: callId || null,
    event_type: eventType,
    endedReason: endedReason,
    startedAt: startedAt,
    endedAt: endedAt,
    transcript: transcript,
    recordingUrl: recordingUrl,
    summary: summary,
    durationMs: durationMs,
    durationSeconds: durationSeconds,
    cost: cost,
    customer_number: customer.number || null,
    customer_name: customer.name || null,
    metadata: metadata,
    artifact: artifact,
    structuredOutputs: structuredOutputs,
    transfers: transfers,
    _raw: envelope
  };
  return item;
});

return items.map(item => {
  const root = item.json || {};
  const structuredOutputs = root.structuredOutputs || {};
  let out = {
    nomenclatura: null,
    motivo: null,
    es_familiar: null,
    contactoalo: null,
    contactoefectivo: null,
    sentimiento: null,
    resumen_llamada: root.summary || null,
    interes_llamada_ejecutivo: null
  };

  const tryParse = (val) => {
    if (!val) return val;
    if (typeof val === 'object' && !Array.isArray(val)) return val;
    if (typeof val === 'string' && (val.trim().startsWith('{') || val.trim().startsWith('['))) {
      try { return JSON.parse(val); } catch (e) {}
    }
    return val;
  };

  const normalize = (name) => String(name || '').toLowerCase().replace(/[\s_]+/g, '');

  for (const [uuid, output] of Object.entries(structuredOutputs)) {
    const name = normalize(output.name);
    const result = tryParse(output.result);

    if (name === 'estadogestionutpl' && typeof result === 'object') {
      out.nomenclatura = result.id_nomenclatura || result.nomenclatura || out.nomenclatura;
      out.motivo = result.id_motivo || result.motivo || out.motivo;
    }
    if (name === 'sentimientocliente') {
      out.sentimiento = typeof result === 'string' ? result : null;
    }
    if (name === 'esfamiliar') {
      out.es_familiar = typeof result === 'string' ? result : null;
    }
    if (name === 'contactoalo') {
      out.contactoalo = typeof result === 'string' ? result : null;
    }
    if (name === 'contactoefectivo') {
      out.contactoefectivo = typeof result === 'string' ? result : null;
    }
    if (name === 'resumenllamada') {
      out.resumen_llamada = typeof result === 'string' ? result : (result?.resumen || out.resumen_llamada);
    }
    if (name === 'interescontactoejecutivo') {
      out.interes_llamada_ejecutivo = typeof result === 'string' ? result : null;
    }
  }

  if (!out.interes_llamada_ejecutivo) {
    out.interes_llamada_ejecutivo = 'NO_APLICA';
  }

  for (const [k, v] of Object.entries(out)) {
    if (v !== undefined) item.json[k] = v;
  }

  return item;
});

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const endedReason = String(item.json.endedReason || '').toLowerCase();

  // Parsear Estado_Gestion_UTPL desde structured outputs para extraer codigo de nomenclatura
  const structuredOutputs = item.json.structuredOutputs || {};
  const estadoGestionOutput = structuredOutputs['3723ad72-ac27-43ac-8a6f-8edaf18d28f6'];
  let parsedNomenclatura = '';
  let parsedMotivo = '';
  if (estadoGestionOutput && typeof estadoGestionOutput.result === 'string') {
    const full = estadoGestionOutput.result.trim();
    const slashIdx = full.indexOf('/');
    if (slashIdx >= 0) {
      parsedMotivo = full.trim();
      const afterSlash = full.substring(slashIdx + 1).trim();
      const codeMatch = afterSlash.match(/ (NUE|ACE|IND|VLL|NIN|NC) /i);
      if (codeMatch) {
        parsedNomenclatura = codeMatch[1].toUpperCase();
      }
    }
  }

  // Fallback: si no hay structured output y es un caso de no-contacto/error, motivo por defecto
  if (!parsedMotivo && (
    endedReason.includes('voicemail') || endedReason.includes('silence') ||
    endedReason.includes('error') || endedReason.includes('failed') ||
    endedReason.includes('providerfault') || endedReason.includes('service-unavailable') ||
    endedReason.includes('timeout') || endedReason.includes('busy') ||
    endedReason.includes('declined') || endedReason.includes('no-answer') ||
    endedReason.includes('wrong-number') || endedReason.includes('503') ||
    !item.json.endedAt || Number(item.json.cost) === 0
  )) {
    parsedMotivo = 'NC - No Contacto';
    parsedNomenclatura = 'NC';
  }

  const nom = String(item.json.nomenclatura || parsedNomenclatura || '').trim().toUpperCase();
  const retryNoms = cfg.retryNomenclaturas || ['NC', 'VLL'];
  const noContactReasons = ['voicemail', 'no-answer', 'busy', 'failed', 'error', 'timeout', 'declined', 'wrong-number', 'providerfault', 'service-unavailable', '503', '500', '408', '486', '480'];

  // CLASIFICA EL ESTADO Y GENERA LA QUERY EN UN SOLO PASO
  let estadoFlujo, statusSugerido, nomenclatura, fechaReagenda;

  if (noContactReasons.some(r => endedReason.includes(r))) {
    nomenclatura = 'NC';
    statusSugerido = 'REINTENTAR';
    estadoFlujo = cfg.states.retry;
    const cooldown = 
      endedReason.includes('wrong-number') ? 60 :
      endedReason.includes('voicemail') || endedReason.includes('silence') ? 30 :
      endedReason.includes('busy') || endedReason.includes('declined') || endedReason.includes('no-answer') ? 15 : 10;
    fechaReagenda = new Date(Date.now() + cooldown * 60000).toISOString();
  } else if (retryNoms.includes(nom)) {
    nomenclatura = nom;
    statusSugerido = 'REINTENTAR';
    estadoFlujo = cfg.states.retry;
    fechaReagenda = new Date(Date.now() + 15 * 60000).toISOString();
  } else if (!nom && (Number(item.json.cost) === 0 || !item.json.endedAt)) {
    nomenclatura = 'NC';
    statusSugerido = 'REINTENTAR';
    estadoFlujo = cfg.states.retry;
    fechaReagenda = new Date(Date.now() + 10 * 60000).toISOString();
  } else {
    nomenclatura = nom || null;
    statusSugerido = 'FINAL';
    estadoFlujo = cfg.states.done;
    fechaReagenda = null;
  }

  item.json.estado_flujo = estadoFlujo;
  item.json.status_sugerido = statusSugerido;
  item.json.nomenclatura = nomenclatura;
  item.json.motivo = parsedMotivo || item.json.motivo || null;
  item.json.fecha_reagenda = fechaReagenda;

  // GENERA LA QUERY SQL
  const raw = String(item.json.id_negocio ?? '').trim();
  if (!raw) {
    item.json.query = `SELECT 'skip_no_id_negocio' AS status`;
  } else {
    const idNegocio = raw.replace(/'/g, "''");
    const estado = String(estadoFlujo).replace(/'/g, "''");
    const freag = fechaReagenda ? `'${String(fechaReagenda).replace(/'/g, "''")}'::timestamptz` : 'NULL';
    item.json.query = `
    UPDATE ${cfg.db.schema}.${cfg.db.table}
    SET estado_flujo = '${estado}',
        fecha_reagenda = ${freag},
        updated_at = now()
    WHERE id_negocio = '${idNegocio}'
    RETURNING *;
  `;
  }

  return item;
});

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const endedReason = String(item.json.endedReason || '').toLowerCase();
  const structuredOutputs = item.json.structuredOutputs || {};
  const estadoGestionOutput = structuredOutputs['3723ad72-ac27-43ac-8a6f-8edaf18d28f6'];

  let nomenclatura, motivo, idNomenclatura, estadoFlujo, statusSugerido, fechaReagenda;

  // 1. Extraer nomenclatura y motivo desde structured outputs
  if (estadoGestionOutput && typeof estadoGestionOutput.result === 'string') {
    const full = estadoGestionOutput.result.trim();
    const slashIdx = full.indexOf('/');
    if (slashIdx >= 0) {
      nomenclatura = full.substring(0, slashIdx).trim();
      motivo = full.substring(slashIdx + 1).trim();
      const codeMatch = motivo.match(/\b(NUE|ACE|IND|VLL|NIN|NC)\b/i);
      idNomenclatura = codeMatch ? codeMatch[1].toUpperCase() : null;
    } else {
      nomenclatura = 'NO CONTACTO';
      motivo = 'NC - No Contacto';
      idNomenclatura = 'NC';
    }
  } else {
    nomenclatura = 'NO CONTACTO';
    motivo = 'NC - No Contacto';
    idNomenclatura = 'NC';
  }

  if (idNomenclatura === 'NIN') {
    motivo = 'NIN - No Esta Interesado En Modalidad En Linea';
  }

  // 2. Clasificar estado
  const retryNoms = cfg.retryNomenclaturas || ['NC', 'VLL'];
  const noContactReasons = ['voicemail', 'no-answer', 'busy', 'failed', 'error', 'timeout', 'declined', 'wrong-number', 'providerfault', 'service-unavailable', '503', '500', '408', '486', '480', 'silence-timed-out'];

  if (noContactReasons.some(r => endedReason.includes(r))) {
    nomenclatura = 'NO CONTACTO';
    motivo = 'NC - No Contacto';
    idNomenclatura = 'NC';
    statusSugerido = 'REINTENTAR';
    estadoFlujo = cfg.states.retry;
    const cooldown = 
      endedReason.includes('wrong-number') ? 60 :
      endedReason.includes('voicemail') || endedReason.includes('silence') ? 30 :
      endedReason.includes('busy') || endedReason.includes('declined') || endedReason.includes('no-answer') ? 15 : 10;
    fechaReagenda = new Date(Date.now() + cooldown * 60000).toISOString();
  } else if (retryNoms.includes(idNomenclatura)) {
    statusSugerido = 'REINTENTAR';
    estadoFlujo = cfg.states.retry;
    fechaReagenda = new Date(Date.now() + 15 * 60000).toISOString();
  } else if (!idNomenclatura && (Number(item.json.cost) === 0 || !item.json.endedAt)) {
    nomenclatura = 'NO CONTACTO';
    motivo = 'NC - No Contacto';
    idNomenclatura = 'NC';
    statusSugerido = 'REINTENTAR';
    estadoFlujo = cfg.states.retry;
    fechaReagenda = new Date(Date.now() + 10 * 60000).toISOString();
  } else {
    statusSugerido = 'FINAL';
    estadoFlujo = cfg.states.done;
    fechaReagenda = null;
  }

  // 3. Asignar valores al item
  item.json.nomenclatura = nomenclatura;
  item.json.motivo = motivo;
  item.json.id_nomenclatura = idNomenclatura || null;
  item.json.estado_flujo = estadoFlujo;
  item.json.status_sugerido = statusSugerido;
  item.json.fecha_reagenda = fechaReagenda;

  // 4. Generar query SQL
  const raw = String(item.json.id_negocio ?? '').trim();
  if (!raw) {
    item.json.query = `SELECT 'skip_no_id_negocio' AS status`;
  } else {
    const idNegocio = raw.replace(/'/g, "''");
    const estado = String(estadoFlujo).replace(/'/g, "''");
    const freag = fechaReagenda ? `'${String(fechaReagenda).replace(/'/g, "''")}'::timestamptz` : 'NULL';
    item.json.query = `
    UPDATE ${cfg.db.schema}.${cfg.db.table}
    SET estado_flujo = '${estado}',
        fecha_reagenda = ${freag},
        updated_at = now()
    WHERE id_negocio = '${idNegocio}'
    RETURNING *;
  `;
  }

  return item;
});

return items.map(item => {
  const cfg = $items('CONFIG INICIAL UTPL', 0, 0)[0].json.cfg;
  const raw = String(item.json.id_negocio ?? '').trim();
  if (!raw) {
    item.json.query = `SELECT 'skip_no_id_negocio' AS status`;
    return item;
  }
  const id_negocio = raw.replace(/'/g, "''");
  const estado = String(item.json.estado_flujo || cfg.states.done).replace(/'/g, "''");
  item.json.query = `
    UPDATE ${cfg.db.schema}.${cfg.db.table}
    SET estado_flujo = '${estado}',
        updated_at = now()
    WHERE id_negocio = '${id_negocio}'
    RETURNING *;
  `;
  return item;
});

